// Calculadora de XP do DevEstudos
// Declare as variaveis de entrada
const faceis = 5;
const medias = 3;
const dificeis = 2;
const modulosCompletos = 6;

let total = 0;

const qtdFaceis = faceis < 0 ? 0 : faceis;
const qtdMedias = medias < 0 ? 0 : medias;
const qtdDificeis = dificeis < 0 ? 0 : dificeis;

total += qtdFaceis * 10;
total += qtdMedias * 20;
total += qtdDificeis * 30;

if (modulosCompletos === 6) {
  total += 50;
}

console.log('XP Total: ' + total);
